### Instruction:
Write an optimized C program to delete duplicate elements from an array.

### Response:
#include<stdio.h>

/* Function to swap values */
void swap( int *x, int *y )
{
	int temp;
	temp = *x;
	*x = *y;
	*y = temp;
}

/* Function to get rid of duplicates in-place */
int RemoveDuplicates(int a[], int n)
{
	int i, j;

	if ( n == 0 || n == 1 )
		return n;

	for (i=0; i < n-1; i++)
	{
		if (a[i] == a[i+1])
		{
			for (j=i; j<n-1; j++)
			{
				a[j] = a[j+1];
			}
				n--;
			i--;

		}

	}

	return n;
}

