// Import the SQLite JDBC driver
import java.sql.Connection;
import java.sql.DriverManager;

public class EmployeeDB {

 public static void main(String[] args) {
 try {
 // Create a connection to the database
 String url = "jdbc:sqlite:employees.db";
 Connection conn = DriverManager.getConnection(url);

 // Create the employees table
 String sql = "CREATE TABLE IF NOT EXISTS employees (id INTEGER PRIMARY KEY, name TEXT, address TEXT, salary INTEGER);";
 Statement stmt = conn.createStatement();
 stmt.execute(sql);

 // Add a new employee
 sql = "INSERT INTO employee (name, address, salary) VALUES ('John Smith', '3220 Main Street', '45000');";
 stmt.execute(sql);

 // Remove an employee
 sql = "DELETE FROM employee WHERE id = 4;";
 stmt.execute(sql);

 // Update an employee
 sql = "UPDATE employee SET address='3521 Forest Lane' WHERE id = 3;";
 stmt.execute(sql);

 conn.close();

 } catch (Exception e) {
 System.out.println(e.getMessage());
 }
 }
}

