### Instruction:
Suggest a way to compress an integer value using bitwise operations.

### Response:
// Function to compress an integer using bitwise operations
const compress = (x) => {
    const mask = 0x3
    let compressed = 0
    let count = 0
    while (x != 0) {
        const b1 = (x & mask) << (count * 2)
        compressed |= b1
        x >>= 2
        count++
    }
    return compressed
}

// Input
let x = 30;

// Output
let compressedVal = compress(x);
console.log(compressedVal);

