### Instruction:
Create a React application for a banking website. The application should allow users to add a new account, switch between their existing accounts, and display a live balance of their accounts with currency formatting.

### Response:
import React, { useState, useEffect } from 'react';
import axios from 'axios';

const App = () => {
 const [accounts, setAccounts] = useState([]);
 const [activeAccount, setActiveAccount] = useState(null);

 useEffect(() => {
 axios.get('/accounts')
 .then(res => setAccounts(res.data))
 .catch(err => console.log(err));
 }, []);

const addAccount = () => {
 axios.post('/accounts', { balance: 0 })
 .then(res => setAccounts([...accounts, res.data]))
 .catch(err => console.log(err));
 }

 const switchAccount = (id) => {
 setActiveAccount(id);
 };

 return (
 <div className="App">
 <h1>Banking</h1>
 <div>
 {accounts.map(account => (
 <div key={account.id} onClick={() => switchAccount(account.id)} >
 {account.id} - {account.balance.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}
 </div>
 ))}
 <button onClick={addAccount}>Add Account</button>
 </div>
 <hr />
 {activeAccount && `Current account: ${activeAccount}`}
 </div>
 );
};

export default App;

