Create a function in JavaScript to check if a given value is present in an array.

### Response:
function contains(array, value) {
  // loop over the array elements
  for(let i = 0; i < array.length; i++) {
    // check if value matches current element
    if (array[i] === value) {
      return true;
    }
  }
  // at this point the value was not found
  return false;
}

