bool isValidMatrix(vector<vector<int>> matrix) {
  int num_rows = matrix.size();
  int num_cols;

  // check if all rows contain the same number of columns 
  for(int i = 0; i < num_rows; i++) {
    num_cols = matrix[i].size();
    if(num_cols != matrix[0].size())
      return false;
  }

  return true;
}

