### Instruction:
Design a function to implement a priority queue using a min heap.

### Response:
def min_heapify(array):
    # Moving down through the heap
    for i in reversed(range(len(array)//2)):
        min_headify_recursive(array, i)

def min_headify_recursive(array, i):
    l = 2*i + 1  # Left Child
    r = 2*i + 2  # Right Child

    smallest = i  # Make the Parent node as min
    if l < len(array) and array[l] < array[i]:
        smallest = l
    if r < len(array) and array[r] < array[smallest]:
        smallest = r

    # Replace parent if child is smaller
    if smallest != i:
        array[i], array[smallest] = array[smallest], array[i]
        min_headify_recursive(array, smallest)

def priority_queue(array):
    min_heapify(array)
    return array

