### Instruction:
Design a code in JavaScript to detect all palindromes in a given string.

### Response:
function findPalindromes(str){
    // Array to store all palindromes
    let palindromes = [];

    // Iterate through the characters in the string
    for (let i = 0; i < str.length; i++){
        // Set a range around the current character to look for palindromes
        let max_range = Math.min(i, str.length - (i + 1)); 

        // Initialise the start and end of the range
        let start = i - max_range;
        let end = i + max_range;

        // Loop through the range to detect palindromes
        while (start <= end){
            // Extract the substring around the current character
            let substr = str.substring(start, end + 1); 

            // Check if the substring is a palindrome
            if (isPalindrome(substr)){
                // Save the palindrome in the array
                palindromes.push(substr);
            }

            // Increment the start and end indices
            start += 1;
            end -= 1;
        }
    }

    // Return all palindromes
    return palindromes;
}

function isPalindrome(str){
    // Reverse the string and compare the two
    return str === str.split('').reverse().join('');
}

