// Function to merge two sorted arrays
function mergeArrays($arr1, $arr2)
{ 
    $result = array(); 
    $i = 0; 
    $j = 0; 

    // Loops to iterate through both arrays
    while ($i < count($arr1) &&
           $j < count($arr2)) 
    { 
        // Check if the current element  
        // of first array is smaller than  
        // current element of second array 
        if ($arr1[$i] < $arr2[$j]) 
        { 
            $result[] = $arr1[$i]; 
            $i++; 
        } 

        else
        { 
            $result[] = $arr2[$j]; 
            $j++; 
        } 
    } 

    // Append remaining elements
    // of first array 
    while ($i < count($arr1)) 
    { 
        $result[] = $arr1[$i]; 
        $i++; 
    } 

    // Append remaining elements  
    // of second array 
    while ($j < count($arr2)) 
    { 
        $result[] = $arr2[$j]; 
        $j++; 
    } 

    return $result; 
} 

