### Instruction:
Construct a program in Java for finding all the permutations of a string

### Response:
public class Permutation {
    public static List<String> getPermutations(String str) {
        List<String> permutations = new ArrayList<>();
        generatePermutations(str, 0, str.length() - 1, permutations);
        return permutations;
    }

    private static void generatePermutations(String str, int l, int r, List<String> permutations) {
        if (l == r) {
            permutations.add(str);
            return;
        }

        for (int i = l; i <= r; i++) {
            str = swap(str, l, i);
            generatePermutations(str, l + 1, r, permutations);
            str = swap(str, l, i);

        }
    }

    private static String swap(String str, int l, int r) {
        char[] array = str.toCharArray();
        char temp = array[l];
        array[l] = array[r];
        array[r] = temp;
        return new String(array);
    }

    public static void main(String[] args) {
        List<String> permutations = getPermutations("abc");
        System.out.println(permutations);
    }
}

