Develop a recommendation system using Collaborative Filtering for a movie streaming platform.

### Response:
class RecommendationSystem:

    def __init__(self, user_ratings):
        self.user_ratings = user_ratings

    def generate_similarity_matrix(self):
        similarity_matrix = np.zeros(shape=(len(self.user_ratings), len(self.user_ratings)))
        for index, user_rating in enumerate(self.user_ratings):
            for index2, user_rating2 in enumerate(self.user_ratings):
                if index != index2:
                    similarity_score = 0
                    movies_in_common = 0
                    for movie in user_rating[1]:
                        if movie in user_rating2[1]:
                            similarity_score += abs(user_rating[1][movie] - user_rating2[1][movie])
                            movies_in_common += 1
                    if movies_in_common > 0:
                        similarity_score = similarity_score / movies_in_common
                        similarity_matrix[index][index2] = similarity_score
                    else:
                        similarity_matrix[index][index2] = float('inf')
        return similarity_matrix

    def find_similar_users(self, user_id):
        similarity_matrix = self.generate_similarity_matrix()
        current_user_index = 0
        for index, user_rating in enumerate(self.user_ratings):
            if user_rating[0] == user_id:
                current_user_index = index
                break
        similarity_scores = []
        for index, row in enumerate(similarity_matrix):
            if current_user_index != index:
                similarity_scores.append((self.user_ratings[index][0], row[current_user_index]))
        sorted_similarity_scores = sorted(similarity_scores, key=lambda x: x[1])
        return sorted_similarity_scores[:5]

    def recommend_movies(self, user_id):
        similar_users = self.find_similar_users(user_id)
        recommended_movies = []
        for user in similar_users:
            similar_user_id = user[0]
            for index, user_rating in enumerate(self.user_ratings):
                if user_rating[0] == similar_user_id:
                    for movie in user_rating[1]:
                        if movie not in self.user_ratings[index][1]:
                            recommended_movies.append((movie, user_rating[1][movie]))
        sorted_recommended_movies = sorted(recommended_movies, key=lambda x: x[1], reverse=True)
        return sorted_recommended_movies[:5]

