def get_max_square_matrix(x):
    rows = len(x)
    cols = len(x[0])

    result = [[0 for _ in range(cols)] for _ in range(rows)]

    for i in range(rows): 
        result[i][0] = x[i][0]  

    for i in range(cols): 
        result[0][i] = x[0][i] 

    for i in range(1, rows): 
        for j in range(1, cols): 
            if (x[i][j] == 1):
                result[i][j] =min(result[i][j-1], result[i-1][j], result[i-1][j-1]) + 1
            else: 
                result[i][j] = 0
    m = result[0][0] 
    mij  = [0, 0] 
    for i in range(rows): 
        for j in range(cols): 
            if (m < result[i][j]): 
                m = result[i][j] 
                mij[0] = i 
                mij[1] = j 

    return m, mij[0], mij[1]

