Build a bezier curve drawing routine in JavaScript.

### Response:
// Bezier curve drawing routine in JavaScript
const bezierCurve = (x1, y1, x2, y2) => {
  // Calculate the curve
  const curveX = 3 * (x2 - x1);
  const curveY = 3 * (y2 - y1);

  const midPointX = (x1 + x2) / 2;
  const midPointY = (y1 + y2) / 2;

  const startPoint = { x: x1, y: y1 };
  const controlPoint = { x: midPointX - curveY, y: midPointY - curveX };
  const endPoint = { x: x2, y: y2 };

  // Draw the curve
  const canvas = document.getElementById('canvas');
  const ctx = canvas.getContext('2d');
  ctx.beginPath();
  ctx.moveTo(startPoint.x, startPoint.y);
  ctx.quadraticCurveTo(controlPoint.x, controlPoint.y, endPoint.x, endPoint.y);
  ctx.lineWidth = 1;
  ctx.strokeStyle = 'black';
  ctx.stroke();
  ctx.closePath();
};

