func findFrequentInt(arr: [Int]) -> Int? {
    var freqDic = [Int: Int]()

    for num in arr {
        if let count = freqDic[num] {
            freqDic[num] = count + 1
        }
        else {
            freqDic[num] = 1
        }
    }

    var mostFrequent = 0
    var mostFrequentCount = 0
    for (num, count) in freqDic {
        if count > mostFrequentCount {
            mostFrequent = num
            mostFrequentCount = count
        }
    }
    if mostFrequentCount > 0 {
        return mostFrequent
    }
    else {
        return nil
    }

}

