func findMissingNumber(arr: [Int]) -> Int {
 let n = arr.count + 1
 // calculate sum of all elements from 1 to n
 let sum = n * (n + 1) / 2
 // calculate sum of all elements in the given array
 var arrSum = 0

 for i in arr {
 arrSum += i
 }
 // missing number = (sum of numbers from 1 to n) - (sum of elements in the given array)
 return sum - arrSum
}

