Rewrite the following function so that it uses recursion instead of a loop.

### Response:
def findLargest(numbers, largest=None):
    # set the initial largest number
    if largest == None:
        largest = numbers[0]

    # base case - only one element is left
    if len(numbers) == 1:
        return largest

    # if the next element is larger than largest, update largest
    if numbers[1] > largest:
        largest = numbers[1]

    # recursively call findLargest
    return findLargest(numbers[1:], largest)

