### Instruction:
Could you suggest an algorithm to optimize this function?

### Response:
function getMinDistance(nums) {
  let minDistance = Infinity;
  let leftPointer = 0;
  let rightPointer = nums.length - 1;
  // Sort the array in ascending order
  nums.sort((a, b) => a - b);
  while (leftPointer < rightPointer) {
    const currentDistance = Math.abs(nums[leftPointer] - nums[rightPointer]);
    if (currentDistance < minDistance) {
      minDistance = currentDistance;
    }
    // Move the pointers closer
    leftPointer++;
    rightPointer--;
  }
  return minDistance;
}

