### Instruction:
Generate a code in Swift that takes in two strings and checks if the two strings are anagrams of each other.

### Response:
func isAnagram(string1: String, string2: String) -> Bool {
    let char1 = Array(string1.lowercased())
    let char2 = Array(string2.lowercased())
    if char1.count != char2.count {
        return false
    }

    var result = true
    while result && char1.count > 0 {
        result = char1.contains(char2.last!)
        if result {
            let index = char1.firstIndex(of: char2.last!)
            char1.remove(at: index!)
            char2.popLast()
        }
    }
    return result
}

let string1 = "silent"
let string2 = "listen"
let result = isAnagram(string1: string1, string2: string2)
if result {
    print("The two strings are anagrams of each other.")
} else {
    print("The two strings are not anagrams of each other.")
}

### Instruction:
Write a JavaScript code to generate the following HTML page.

### Response:
"""
Write a JavaScript code to generate the following HTML page
"""

const body = document.querySelector('body')

const headings = ['h1', 'h2', 'h3', 'h4', 'h5', 'h6']
headings.forEach(heading => {
    const el = document.createElement(heading)
    el.innerText = `Heading ${heading}`
    body.appendChild(el)
})

const list = document.createElement('ul')
for(let i=0; i<5; i++){
    const item = document.createElement('li')
    item.innerText = `List item ${i+1}`
    list.appendChild(item)
}
body.appendChild(list)

